    // Check if it's a palindrome
    if (str !== str.split('').reverse().join('')) {
        return false;
    }
    const digitCount = {};
    for (const char of str) {
        const digit = parseInt(char, 10);
        if (digit < 1 || digit > 9) {
            return false;
        }
        digitCount[digit] = (digitCount[digit] || 0) + 1;
    }
    for (const [digit, count] of Object.entries(digitCount)) {
        const d = parseInt(digit, 10);
        if (count !== d) {
            return false;
        }
    }
    // Check if all digits from 1 to maxDigit are present if needed
    const digits = Object.keys(digitCount).map(Number);
    const maxDigit = Math.max(...digits);
    for (let k = 1; k <= maxDigit; k++) {
        if (!digitCount[k] || digitCount[k] !== k) {
            return false;
        }
    }
    return true;
}

function solve(n) {
    let current = n + 1;
    while (true) {
        if (isSpecialNumber(current)) {
            return current;
        }
        current++;
    }
}
